import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);
    }

    @Test
    public void testGetAllowMissingColumnNames() {
        // Given
        boolean expected = true;
        csvFormat = csvFormat.withAllowMissingColumnNames(expected);

        // When
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Then
        assertEquals(expected, result);
    }

    @Test
    public void testGetAllowMissingColumnNames_Default() {
        // Given
        boolean expected = false;

        // When
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Then
        assertEquals(expected, result);
    }

    // Add more test cases for other methods if needed
}
